conditionPrometheusQueryLanguage.query:
sum by ("gen_ai.response.model")(
    increase({
        "__name__"="gen_ai.client.operation.duration_count",
        "location"="${LOCATION}",
        "cluster"="${AGENT_ID}",
        "error.type"!= ""
    }[5m])
)
/
sum by ("gen_ai.response.model")(
    increase({
        "__name__"="gen_ai.client.operation.duration_count",
        "location"="${LOCATION}",
        "cluster"="${AGENT_ID}"
    }[5m])
) > 0.05
